import sys

def solve():
    input_data = sys.stdin.buffer.read().split()
    idx = 0
    t = int(input_data[idx]); idx += 1

    for _ in range(t):
        n = int(input_data[idx]); idx += 1
        a = list(map(int, input_data[idx:idx+n])); idx += n

        pre = [0] * (n + 1)
        for i in range(n):
            pre[i+1] = pre[i] + a[i]

        def feasible(k):
            if k == 0:
                return True
            if k * (k + 1) // 2 > n:
                return False

            INF = float('inf')

            # sf[p] = suffix min for current segment layer
            # Initialize for segment k (length 1)
            sf = [INF] * (n + 2)
            for p in range(n, 0, -1):
                sf[p] = min(sf[p+1], a[p-1])

            # Process segments k-1 down to 1
            for i in range(k-1, 0, -1):
                L = k - i + 1  # length of segment i
                new_sf = [INF] * (n + 2)
                cur_min = INF
                max_s = n - L + 1
                for s in range(max_s, 0, -1):
                    sum_s = pre[s + L - 1] - pre[s - 1]
                    next_pos = s + L
                    if next_pos <= n + 1 and sum_s < sf[next_pos]:
                        if sum_s < cur_min:
                            cur_min = sum_s
                    new_sf[s] = cur_min
                sf = new_sf

            return sf[1] < INF

        # Binary search for max k
        lo, hi = 0, int((-1 + (1 + 8*n)**0.5) / 2)
        # Make sure hi is valid upper bound
        while hi * (hi + 1) // 2 > n:
            hi -= 1

        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1

        print(lo)

solve()

